import React from 'react';
import { View, Text, StyleSheet, SafeAreaView, ScrollView } from 'react-native';
import { COLORS } from '../styles/theme';

export default function ScreenShell({ title, subtitle, children, padded = true, scroll = true, topSpace = false, logo = false }) {
  const Container = scroll ? ScrollView : View;
  return (
    <SafeAreaView style={styles.safe}>
      <Container contentContainerStyle={[styles.container, padded && styles.padded]} style={styles.flex}>
        {topSpace ? <View style={styles.logoSpace} /> : null}
        {logo ? <View style={styles.logoMark}><Text style={styles.logoText}>🐾</Text></View> : null}
        {title ? <Text style={styles.title}>{title}</Text> : null}
        {subtitle ? <Text style={styles.subtitle}>{subtitle}</Text> : null}
        {children}
      </Container>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: COLORS.background },
  flex: { flex: 1 },
  container: { flexGrow: 1 },
  padded: { padding: 20 },
  logoSpace: { height: 96 },
  logoMark: {
    width: 92,
    height: 92,
    borderRadius: 28,
    backgroundColor: COLORS.surface,
    alignItems: 'center',
    justifyContent: 'center',
    alignSelf: 'center',
    marginBottom: 16,
    borderWidth: 1,
    borderColor: COLORS.border
  },
  logoText: { fontSize: 40 },
  title: { fontSize: 34, fontWeight: '800', color: COLORS.text, textAlign: 'center' },
  subtitle: { marginTop: 10, fontSize: 15, color: COLORS.muted, textAlign: 'center', lineHeight: 22 }
});
